var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"저 사람은…… 황태자……? 살아 있었어?","JPN":"あの人は……皇太子……？　生きていたの？","ENG":"That's... the Crown Prince...! He's alive...?","TWN":"那個人是……皇太子……？他還活著？"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"게다가 병사들까지 끌고 왔어.","JPN":"それに、兵士まで引き連れてきてる。","ENG":"He even brought soldiers.","TWN":"還是帶著士兵過來的。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"잠깐, 그렇다면 부사장님이랑 다른 사람들은…….","JPN":"待って、じゃあ副社長や他のみんなは……","ENG":"Wait, then the Vice President and the others...","TWN":"等等，那副總和其他人不就……"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"미나 양, 동요하지 마세요.","JPN":"ミナさん、落ち着いてください。","ENG":"Keep calm, Mina.","TWN":"米娜，別動搖。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"엄격하게 통솔되지 않는 군대를 각개격파하는 건 그리 어려운 일도 아니지.","JPN":"統率の甘い軍隊を分散させ潰していくのはそう難しいことではない。","ENG":"It's not so hard to break through an army that lacks a proper leader.","TWN":"將沒有嚴格統率的軍隊逐個擊破，也不是什麼難事。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 경. 마르티네즈 공. 저 자들을 포위해라.","JPN":"バーミンガム卿。マルチネス卿。あの者たちを包囲しろ。","ENG":"Sir Allen. Marquise Martinez. Surround them.","TWN":"艾倫卿，馬汀尼茲侯爵，包圍那些人。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"명을 받들겠습니다, 전하.","JPN":"かしこまりました、殿下。","ENG":"As you wish, Your Highness.","TWN":"遵命，殿下。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L10_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전군! 전개!","JPN":"全軍！　展開！","ENG":"All troops! Forward!","TWN":"全軍！展開！"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그나저나…… 그 여자가 결국 일을 저지르고 말았군.","JPN":"それにしても……あの女が結局はやらかしたか。","ENG":"On another note... It seems that woman finally did it.","TWN":"話說回來……那個女人最終還是闖禍了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"전하…… 저는…….","JPN":"殿下……僕は……","ENG":"Your Highness, I...","TWN":"殿下……我……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"끝까지 적 앞에서 약한 모습을 보일 셈인가, 평민.","JPN":"いつになったら敵の前で冷静になりきれるんだ、平民。","ENG":"Do you still intend to show your weakness to the enemy, peasant?","TWN":"你想在敵人面前一直表現出軟弱的樣子嗎，平民？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"예상은 했다만, 아직도 마음을 다잡지 못하고 있었군.","JPN":"予想はしていたが、まだ心が揺らいでいるようだな。","ENG":"I assumed so, but it's clear that you haven't made up your mind.","TWN":"雖然早預料到了，但是你現在還沒下定決心啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"네 공연은 끝이다.","JPN":"貴様の芝居はここまでだ。","ENG":"Your phony show is over.","TWN":"你的演出結束了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하다못해 네가 지키고 있어야 할 옥좌로 돌아가라. 그 여자와 함께.","JPN":"せめて貴様が守るべき玉座に戻れ。その女と共に。","ENG":"Go back to the throne that you should be sitting on. Take the girl with you.","TWN":"你還是回到你的那個寶座上去吧，和那個女人一起。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……죄송합니다, 전하. 뒤를 부탁드립니다.","JPN":"……申し訳ありません、殿下。後はお願いします。","ENG":"...Forgive me, Your Highness. I leave the rest to you.","TWN":"對不起，殿下。後面就拜託您了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배, 방금 전보다 상황이 더 안 좋아진 것 같아.","JPN":"先輩、さっきよりもっと状況が悪くなったんじゃないかな。","ENG":"I think things just got worse, Shiyoon.","TWN":"局勢好像變得比剛才更差了，前輩……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"확실히 독 안에 든 쥐네요. 이럴 줄 알았으면 남은 휴가라도 모두 쓰고 올 걸 그랬어요.","JPN":"確かに八方塞がり状態ですね。こうなるとわかっていたら、残りの有給を使い切っておくんでした。","ENG":"We're definitely cornered here. I should have used all of my remaining days off if things were going to end like this.","TWN":"我們現在等於是甕中之鱉呢。早知道這樣，我就把剩下的休假都用完再來了，哈哈。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그렇게 농땡이 피우면서 남은 휴가가 있었어……?","JPN":"あんなにサボっておいて、まだ有給が残っていたんだ……？","ENG":"You still have days off after slacking off so much...?","TWN":"偷了這麼多次懶，居然還有剩下的休假……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흠. 제 발로 막다른 곳까지 들어온 노고는 칭찬해 주지.","JPN":"ふむ。自ら袋小路に飛び込んでくるとは、ご苦労だったな。","ENG":"Hmm. I admit it took an effort to corner yourselves like this.","TWN":"嗯，對於你們的自尋死路，我要表示讚許。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 경, 늑대는 살려둬라.","JPN":"アレン、狼は生かしておけ。","ENG":"Sir Allen, keep the Wolf alive.","TWN":"艾倫卿，留狼一條命。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"저 도둑 고양이와 소년은 여기서 처단한다.","JPN":"あの泥棒猫と少年はここで始末する。","ENG":"Take down the stray cat and the boy.","TWN":"那個野貓和年輕人就地正法。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"칫…… 저 느끼한 얼굴에 한 발 먹여 줬여야 하는데.","JPN":"ちっ……あの濃い顔に一発食らわせたかったのに。","ENG":"Tsk... I should’ve made a dent in that cheesy face of his.","TWN":"嘖……就應該對那張油膩的臉蛋踢一腳的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이봐, 마음대로 하게 놔둘 거 같아?!","JPN":"ちょっと、好きにはさせないよ！？","ENG":"Hey, who says we're going to let you?","TWN":"喂，你以為我們會讓你為所欲為嗎？！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"승자의 특권이라는 거다, 저주받은 늑대여.","JPN":"これは勝者の特権だ、呪われた狼よ。","ENG":"It is called the privilege of victory, Cursed Wolf.","TWN":"這是贏家的特權，受詛咒的狼。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"너무 서운해하지 말도록. 네 최후에 어울리는 무대는 이미 마련되어 있으니.","JPN":"そうがっかりするな。貴様の最期にふさわしい舞台はすでに用意してある。","ENG":"Do not fret. I have prepared the perfect stage that is well suited for your demise.","TWN":"別太難過。我已經為你的結局準備好合適的舞台了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"음……!?","JPN":"ん……！？","ENG":"Mmm...?!","TWN":"嗯……！？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"큭! 이 공격은……?","JPN":"クッ！　この攻撃は……？","ENG":"Kgh! This attack...?!","TWN":"咳！這個攻擊……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"이런?! 기사들! 전하를 호위하라!","JPN":"何ッ！？　騎士は殿下を護衛しろ！","ENG":"No! Knights! Protect His Highness!","TWN":"可惡？！騎士們！保護殿下！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저 불빛은……","JPN":"あの光は……","ENG":"That light...","TWN":"那道光……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 아무래도 미나 양 예상이 들어맞은 것 같네요.","JPN":"ハハ、どうやらミナさんの予想が当たったようですね。","ENG":"Ha ha, it turns out Mina's guess hit the mark.","TWN":"哈哈，看來米娜的想法是對的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"안 그러신 척 하면서 극적인 상황을 참 좋아하신다니까요.","JPN":"そういう素振りは見せませんが、師匠は劇的な状況が大好きなんですよ。","ENG":"Master loves dramatic situations, even if she pretends like she doesn’t.","TWN":"師父雖然假裝不在意，實際上卻非常喜歡戲劇性的演出呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"생각해 보니 지난번에 해 주지 못한 말이 있더군, 황태자.","JPN":"考えてみたんだが、前回は言いそびれたことがあった、皇太子。","ENG":"Thinking back... there was something I needed to tell you, Crown Prince.","TWN":"我想了一下，上次有句話沒對你說，皇太子。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"공연을 보는 네 식견은 아주 고리타분해.","JPN":"貴様の芝居の見かたはありきたりでつまらないぞ。","ENG":"You have old-fashioned insight with performances.","TWN":"你看戲的眼光太老套了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"소대장!!","JPN":"小隊長！！","ENG":"Commander!","TWN":"小隊長！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"잘도 여기까지 왔군, 신입.","JPN":"よくここまでたどり着いたな、新人。","ENG":"You made it here, rookie.","TWN":"你來得正好，新人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"내가 자리 비운 동안 별일 없었나?","JPN":"私がいない間、何か問題はなかったか？","ENG":"So, any news?","TWN":"我不在的時候沒什麼事吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"……응. 소대장 없이도 버틸 만하던데.","JPN":"……うん。小隊長がいなくても全然やれたよ。","ENG":"...No. We were doing fine without you.","TWN":"……不，小隊長不在的時候我們也堅持住了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"흥. 칭찬해 주기라도 바라는 거냐. 아직 갈 길이 멀군.","JPN":"ふん。褒めてくれとでもというのか。まだまだだな。","ENG":"Hmph. Don't expect a compliment from me. You clearly have a long way to go.","TWN":"哼，你是希望我誇你嗎？你們要走的路還很長。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"어떻게……!","JPN":"どうやって……！","ENG":"How...!","TWN":"怎麼會……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"당신이 어떻게 성역에 침입한 거지? 맨몸으로 허수 공간에 내던져졌으면서!","JPN":"どうやってあなたが聖域に侵入できたんだ？　生身で虚数空間に飛ばされたのに！","ENG":"How did you invade the sanctuary? You were thrown into the imaginary space!","TWN":"你是怎麼入侵聖域的？你明明已經被扔進虛數空間了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너희가 떠올릴 법한 함정을 다른 마왕들이 사용한 적 없을 줄 알았나?","JPN":"お前たちに使える罠を、他の魔王たちは使っていないとでも思ったか？","ENG":"Never considered that your methods were used by other Demon Lords, did you?","TWN":"你以為其他魔王就沒用過你們想到的陷阱嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"레비아탄을 안배로 활용하는 건, 다소 의외였지만 말이다.","JPN":"レヴィアタンを使ったのは、少し意外だったがな。","ENG":"Although I do admit, how using Leviathan was unexpected.","TWN":"不過竟然會看到利維坦，多少讓我有些意外。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"말도 안 돼……. 그 순간을 이용한다고?  ","JPN":"馬鹿な……あの一瞬を利用しただと？  ","ENG":"Impossible... In that split second of time?","TWN":"不可能……你利用了那個瞬間？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"전쟁 놀이에 익숙해져서 중요한 교훈을 잊었군.","JPN":"戦争ごっこに慣れすぎたせいで、大事な教訓を忘れたのか。","ENG":"You forgot the most important lesson, getting used to play-war.","TWN":"因為習慣了戰爭，所以你忘了重要的教訓啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"전쟁에서 가장 위험한 순간은……","JPN":"戦争で最も危険な瞬間は……","ENG":"The most dangerous moment in war...","TWN":"戰爭中最危險的瞬間……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"승리를 확신했을 때다. 당신이 용병대장 행세를 하던 시절 입버릇이었죠.","JPN":"勝利を確信した瞬間だ。あなたが傭兵隊長のふりをしていた頃に口癖のように言っていましたね。","ENG":"...Is the moment when you are sure of your victory. Your words, from back when you took the role of Mercenary Captain.","TWN":"就是確信能勝利的時候。這是你當傭兵隊長時的口頭禪。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하하하하!","JPN":"はっはっはっは！","ENG":"Ha ha ha ha ha!","TWN":"哈哈哈哈哈！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그렇지. 그대다운 지적이야.","JPN":"そうだ。貴様らしい指摘だ。","ENG":"Right. A valid remark.","TWN":"是啊，這種指責是你的風格。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"전쟁의 한복판에 나서야 비로소 싸울 가치가 있는 모습을 보여 주는군, 발키리.","JPN":"いざ戦争の真っ最中になって、ようやく戦い甲斐のある様を見せるのだな、ヴァルキリー。","ENG":"I see that you show your true worth in battle, Valkyrie.","TWN":"只有站到戰爭的中心，你才會顯露出真正有價值的一面，女武神！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"알트 소대장, 싸울 수 있겠나?","JPN":"アルト小隊長、戦えるか？","ENG":"ALT Commander, are you fit for battle?","TWN":"阿爾特小隊長，你還能打嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"무리만 하지 않는다면요. 부상이 심해서.","JPN":"無理さえしなければなんとか。深い怪我を負ってしまったので。","ENG":"As long as I don't overwork myself. My injuries are pretty severe.","TWN":"硬撐的話還可以。傷口有些嚴重。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"하지만 그런 대답을 원하신 건 아니겠죠, 펜릴 소대장님?","JPN":"でも、こんな答えが聞きたかったんじゃありませんよね？　フェンリル小隊長。","ENG":"But that's not the answer you want, is it? Fenrir Commander.","TWN":"不過你應該不想聽到這種答案吧，芬里爾小隊長？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"여기는 놈들의 영역이다. 일개 병졸들이라도 우습게 볼 수준은 아니게 되지.","JPN":"ここは奴らの領域だ。雑魚でも侮れないレベルになる。","ENG":"This is their domain. No enemy should be overlooked or underestimated.","TWN":"這裡是那些傢伙的領域。一兵一卒的實力都不容小覷。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"지켜 줄 틈은 없을 거다. 재주껏 살아남도록.","JPN":"守ってやれるような余裕はないぞ。自分でなんとか生き延びろ。","ENG":"I won't have time to save you. Survive on your own.","TWN":"我沒空保護你，你盡自己的努力活下來。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"……복귀하면 사내 고충처리 위원회에 신고해야겠네. 직원 학대로.","JPN":"……復帰したら社内の苦情処理部署に報告しますよ。社員虐待で。","ENG":"...I should report her to HR when we get back. For abusing employees.","TWN":"……如果能回去，我一定向公司高層投訴，說你虐待職員。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"너무 투덜거리지 마, 알트 소대장님. 나 같은 평사원도 열심히 하잖아.","JPN":"文句言っても仕方ないよ、アルト小隊長。私みたいな平社員でも頑張っているんだから。","ENG":"Don't be so grumpy, ALT Commander. Even a normal employee like me works hard!","TWN":"別太發牢騷了，阿爾特小隊長。像我這樣的普通職員也在努力呢，不是嘛。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 스승님께서 돌아오시다니 정말 기쁜 순간이네요.","JPN":"はは、師匠が戻ってくるなんて、本当に喜ばしい瞬間ですね。","ENG":"Ha ha, I'm so glad that you're back, Master.","TWN":"哈哈，師父回來了，這可真是值得高興的時刻。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그럼 전 잠시 휴식을 취하고 와도 될까요? 새로운 지병으로 과호흡증이 생길 예정이라서요.","JPN":"では僕は少し休んできてもよろしいでしょうか？　過呼吸症候群という新しい持病ができる予定なので。","ENG":"Now, may I take a rest for a while? I'm planning on getting hyperventilated from a new chronic pain.","TWN":"那我可以休息一下嗎？我現在因為慢性疼痛而要換上過度呼吸症了呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그럼 정식으로 휴가계를 제출해라. 그 때는 고려해 보도록 하지.","JPN":"ならば正式に有給申請をしろ。そしたら少しは考えてやる。","ENG":"Submit a formal vacation request. Then I'll consider.","TWN":"那你就正式提交休假報告。到時候我會考慮看看。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"호오, 그 거짓말 혹시 정말인가요?","JPN":"ほお、その嘘ってもしかして本当ですか？","ENG":"Ah, are you sure you're not lying?","TWN":"喔呵，這個是假話還是真話？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그래. 단, 이번 작전을 끝낸 뒤에.","JPN":"ああ。ただし、この作戦が終わってからだ。","ENG":"Yes. After we finish this operation.","TWN":"是真的，不過，要等這次作戰結束以後。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그러실 줄 알았어요.","JPN":"……ですよね。","ENG":"I knew you would say that.","TWN":"我就知道會這樣。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"어쩔 수 없죠. 누구 지시신데.","JPN":"仕方ないですね。他でもない、師匠の命令ですから。","ENG":"I guess I don't have a choice. Direct orders.","TWN":"沒辦法，畢竟是直接命令嘛。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"전열은 제대로 정비했나, 발키리?","JPN":"戦列の整備は万端か、ヴァルキリー？","ENG":"All done with setting up your forces, Valkyrie?","TWN":"看來你整頓好隊伍了，女武神。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"전 대원, 이번 작전의 목표는 마왕 네헤모트의 요격이다.","JPN":"全隊員、今回の作戦の目標は魔王ネヘモトの迎撃だ。","ENG":"All members, our objective is to take down Nehemoth, the Demon Lord.","TWN":"全體隊員，這次作戰的目標是攔截魔王貝赫莫特。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"부디 이 무대에서 양측이 후회 없는 전투를 벌일 수 있길 바란다.","JPN":"この舞台が両陣営にとって悔いなき戦いになることを願う。","ENG":"I hope this stage brings a battle that we can both be satisfied with.","TWN":"希望雙方能在這次的舞台上展開一場無悔的戰鬥。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"모든 방해물은 배제해도 좋다.","JPN":"全ての障害物は排除してもいいぞ。","ENG":"You may overlook all obstacles.","TWN":"除此之外一切障礙都可以排除。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"전군!","JPN":"全軍！","ENG":"All troops!","TWN":"全軍！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"펜릴 소대!","JPN":"フェンリル小隊！","ENG":"Fenrir Squad!","TWN":"芬里爾小隊！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"출정하라!","JPN":"出征！","ENG":"Engage!","TWN":"出征！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"작전 개시.","JPN":"作戦開始。","ENG":"Commence operation.","TWN":"開始作戰。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};